export const getUpdateSetupUrl = (id: string,) => {




  return `/api/setups/${id}`
}

/**
 * @summary Update an alignment setup
 */
export const updateSetup = async (id: string,
    setupUpdate: SetupUpdate, options?: RequestInit): Promise<Setup> => {

  return customFetch<Setup>(getUpdateSetupUrl(id),
  {
    ...options,
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(
      setupUpdate,)
  }
);}




export const getUpdateSetupMutationOptions = <TError = ErrorType<ErrorEnvelope>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof updateSetup>>, TError,{id: string;data: BodyType<SetupUpdate>}, TContext>, request?: SecondParameter<typeof customFetch>}
): UseMutationOptions<Awaited<ReturnType<typeof updateSetup>>, TError,{id: string;data: BodyType<SetupUpdate>}, TContext> => {

const mutationKey = ['updateSetup'];
const {mutation: mutationOptions, request: requestOptions} = options ?
      options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey ?
      options
      : {...options, mutation: {...options.mutation, mutationKey}}
      : {mutation: { mutationKey, }, request: undefined};




      const mutationFn: MutationFunction<Awaited<ReturnType<typeof updateSetup>>, {id: string;data: BodyType<SetupUpdate>}> = (props) => {
          const {id,data} = props ?? {};

          return  updateSetup(id,data,requestOptions)
        }






  return  { mutationFn, ...mutationOptions }}

    export type UpdateSetupMutationResult = NonNullable<Awaited<ReturnType<typeof updateSetup>>>
    export type UpdateSetupMutationBody = BodyType<SetupUpdate>
    export type UpdateSetupMutationError = ErrorType<ErrorEnvelope>

    /**
 * @summary Update an alignment setup
 */
export const useUpdateSetup = <TError = ErrorType<ErrorEnvelope>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof updateSetup>>, TError,{id: string;data: BodyType<SetupUpdate>}, TContext>, request?: SecondParameter<typeof customFetch>}
 ): UseMutationResult<
        Awaited<ReturnType<typeof updateSetup>>,
        TError,
        {id: string;data: BodyType<SetupUpdate>},
        TContext
      > => {
      return useMutation(getUpdateSetupMutationOptions(options));
    }

